import { IMessageComposer } from '@nitrots/nitro-renderer';

export class PassiveModeComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(enabled: boolean) {
        this._data = [enabled];
        console.log('[📦] PassiveModeComposer sent →', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
